import { Router } from 'express';
import { body } from 'express-validator';
import { createSubmission, markTaskCompleted } from '../controllers/submissionController.js';
import { authenticate, authorize } from '../middleware/auth.js';
import { validate } from '../middleware/validate.js';
import { asyncHandler } from '../utils/asyncHandler.js';
const router = Router();
router.post('/', authenticate, authorize('student'), [body('taskId').notEmpty(), body('textResponse').notEmpty().withMessage('Text response required'), validate], asyncHandler(createSubmission));
router.post('/complete', authenticate, authorize('student'), [body('taskId').notEmpty(), validate], asyncHandler(markTaskCompleted));
export default router;
